CustomFunction.Calculation:
// Appends a raw SQL expression to the ORDER BY clause verbatim.
// Useful for RAND(), CASE expressions, or function-based ordering.
// Example: QueryOrderByRaw_cf ( query ; "RAND()" )
Let
(
[
_orderByCount = JSONGetElement ( query ; "orderByCount" ) ;
_orderByObj = JSONSetElement ( "{}" ;
	[ "type" ; "raw" ; JSONString ] ;
	[ "sql" ; rawSql ; JSONString ]
	) ;
_q1 = JSONSetElement ( query ; "orderBys[" & _orderByCount & "]" ; _orderByObj ; JSONObject ) ;
_q2 = JSONSetElement ( _q1 ; "orderByCount" ; _orderByCount + 1 ; JSONNumber )
];
_q2
)
